using System;
using System.Collections.Generic;
using NamedEntityRecognitionModule;

namespace NLP
{
    public class Main
    {
        private readonly NamedEntityRecognitionModule namedEntityRecognitionModule;

        public Main()
        {
            this.namedEntityRecognitionModule = new NamedEntityRecognitionModule();
        }

        public void AnalyzeText(string text)
        {
            var namedEntities = this.namedEntityRecognitionModule.Analyze(text);
            foreach (var namedEntity in namedEntities)
            {
